"  const [activeTab, setActiveTab] = useState('academic')
  const [classes, setClasses] = useState([])
  const [selClassId, setSelClassId] = useState('')
  const [date, setDate] = useState(new Date().toISOString().slice(0,10))
  const [attendanceData, setAttendanceData] = useState(null)
  const [students, setStudents] = useState([])
  const [selStudentId, setSelStudentId] = useState('')
  const [loading, setLoading] = useState(false)

  // Academic report states
  const [academicReport, setAcademicReport] = useState(null)
  const [loadingAcad, setLoadingAcad] = useState(false)

  useEffect(() => {
    classesApi.list().then(r => {
      const list = r.data.data || []
      setClasses(list)
      if (list.length) setSelClassId(String(list[0].id))
    }).catch(console.error)
  }, [])

  useEffect(() => {
    if (!selClassId) return
    setLoading(true)
    Promise.all([
      attendanceApi.list({ classId: selClassId, date }),
      studentsApi.list({ classId: selClassId, limit: 200 }),
    ]).then(([ar, sr]) => {
      setAttendanceData((ar.data.data || [])[0] || null)
      const list = sr.data.data || []
      setStudents(list)
      if (list.length) {
        setSelStudentId(String(list[0].id))
      } else {
        setSelStudentId('')
      }
    }).catch(console.error).finally(() => setLoading(false))
  }, [selClassId, date])"

